using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ─── CalculateTotal: DataRow tests ───────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero price returns zero")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity returns zero")]
    [DataRow(100.00, 2, 1.0, 400.00, DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expectedTotal)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expectedTotal, result);
    }

    // ─── CalculateTotal: DynamicData for complex scenarios ───────────────────

    public static IEnumerable<object[]> BulkOrderScenarios
    {
        get
        {
            yield return new object[] { 5.99m, 100, 0.07m, 640.93m, "Large quantity order" };
            yield return new object[] { 1999.99m, 1, 0.0925m, 2184.99m, "High-value single item" };
            yield return new object[] { 0.01m, 1, 0.0m, 0.01m, "Minimum non-zero price" };
            yield return new object[] { 49.99m, 12, 0.05m, 629.87m, "Annual subscription" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(BulkOrderScenarios), DynamicDataSourceType.Property)]
    public void CalculateTotal_BulkOrders_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expectedTotal, string scenario)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expectedTotal, result, $"Failed for scenario: {scenario}");
    }

    // ─── CalculateTotal: invalid input tests ─────────────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price throws")]
    public void CalculateTotal_NegativePrice_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below 0 throws")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above 1 throws")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ─── ApplyDiscount: DataRow tests ────────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount returns full price")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% discount")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% discount returns zero")]
    [DataRow(49.99, 25.0, 37.4925, DisplayName = "Fractional result preserved")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price stays zero")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        double price, double discountPercent, double expectedPrice)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expectedPrice, result);
    }

    // ─── ApplyDiscount: DynamicData from method ──────────────────────────────

    public static IEnumerable<object[]> TieredDiscountScenarios()
    {
        // Simulating tiered pricing: higher spend → bigger discount
        yield return new object[] { 50.00m, 5.0m, 47.50m, "Bronze tier (5%)" };
        yield return new object[] { 150.00m, 15.0m, 127.50m, "Silver tier (15%)" };
        yield return new object[] { 500.00m, 25.0m, 375.00m, "Gold tier (25%)" };
        yield return new object[] { 1000.00m, 35.0m, 650.00m, "Platinum tier (35%)" };
    }

    [TestMethod]
    [DynamicData(nameof(TieredDiscountScenarios), DynamicDataSourceType.Method)]
    public void ApplyDiscount_TieredDiscounts_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expectedPrice, string tier)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expectedPrice, result, $"Failed for tier: {tier}");
    }

    // ─── ApplyDiscount: invalid input tests ──────────────────────────────────

    [TestMethod]
    [DataRow(100.00, -1.0, DisplayName = "Negative discount throws")]
    [DataRow(100.00, 100.01, DisplayName = "Discount over 100% throws")]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRange(
        double price, double discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent));
    }
}

